insert into im_cat_causal_impedimento values (1, 'I. A quien intente obtener un pasaporte o documento de identidad y viaje en contravención con las disposiciones del presente Reglamento;', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (2, 'II. A quien presente ante la Secretaría información o documentos falsos, previa verificación con la autoridad competente;', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (3, 'III. Cuando alguna de las personas que ejerce la patria potestad sobre una persona menor de edad, o tutela sobre una persona mayor de edad, exponga su temor de que otro pretenda sustraerlo del país sin su consentimiento;', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (4, 'IV. A quien haya obtenido un pasaporte mexicano o documento de identidad y viaje con documentos o', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (5, 'V. A quien sea solicitado en extradición internacional;', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (6, 'VI. A quien alguna autoridad judicial o administrativa, solicite se le restrinja la expedición o renovación de Pasaporte o Documento de Identidad y Viaje o se impida la salida del territorio nacional;', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (7, 'VII. A quien intente o haya obtenido un Pasaporte o Documento de Identidad y Viaje usurpando la identidad de otra persona, ostentando la nacionalidad mexicana no teniendo derecho a ella u ostente una nacionalidad que no le corresponde, y', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (8, 'VIII. A quien cuente con dos o más inscripciones de actos del estado civil ante la oficina del registro civil mexicana u Oficina Consular que se refieran al mismo hecho, sin haber anulado legalmente uno de ellos.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (9, 'IX. En los casos en que se modifique el nombre del solicitante derivado de un procedimiento judicial o administrativo, la Secretaría decretará un impedimento administrativo al nombre anterior del solicitante, como medida de protección a la identidad jurídica del mismo.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (10, 'Por acreditar nacionalidad e identidad.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (11, 'Por presentar documentación verificada con resultado correcto.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (12, 'A solicitud de quién ejerce patria potestad o tutela.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (13, 'A petición de autoridad judicial.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (14, 'Por ser mayor de edad.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (15, 'Por acreditar la nulidad del registro de nacimiento obtenido indebidamente.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (16, 'Por acreditar plenamente la nacionalidad mexicana.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (17, 'Por acreditar plenamente su identidad.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (18, 'Por acreditar filiación paterna o materna.', false, default, null, CURRENT_TIMESTAMP, null);
insert into im_cat_causal_impedimento values (19, 'Otra', false, default, null, CURRENT_TIMESTAMP, null);
